/**
 * Checks if a number is prime.
 *
 * @param num The number to check.
 * @return True if the number is prime, false otherwise.
 */
bool isPrime(int num) {
    if (num <= 1) {
        return false;
    }

    for (int i = 2; i * i <= num; ++i) {
        if (num % i == 0) {
            return false;
        }
    }

    return true;
}

/**
 * Finds all prime numbers up to a given limit.
 *
 * @param limit The upper limit.
 * @return A list of prime numbers.
 */
void findPrimes(int limit) {
    for (int i = 2; i <= limit; ++i) {
        if (isPrime(i)) {
            std::cout << i << std::endl;
        }
    }
}

int main() {
    try {
        int num;
        std::cout << "Enter a number: ";
        std::cin >> num;

        if (isPrime(num)) {
            std::cout << num << " is a prime number." << std::endl;
        } else {
            std::cout << num << " is not a prime number." << std::endl;
        }

        int limit;
        std::cout << "Enter the upper limit: ";
        std::cin >> limit;

        std::cout << "Prime numbers up to " << limit << ":" << std::endl;
        findPrimes(limit);
    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
        return 1;
    }

    return 0;
}
```

**Explanation**

*   The `isPrime` function checks if a number is prime by iterating up to its square root and checking for divisibility.
*   The `findPrimes` function finds all prime numbers up to a given limit by calling `isPrime` for each number.
*   In the `main` function, the program checks if a user-input number is prime and finds all prime numbers up to a given limit. It includes error handling for exceptions.

